import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is VAT?", a: "VAT, or value added tax, is a consumption tax added at different stages of production and usually paid by the final customer." },
  { q: "How do you calculate VAT?", a: "To add VAT, multiply the price excluding VAT by the VAT rate. To remove VAT, divide the VAT-inclusive price by one plus the VAT rate." },
  { q: "What is the difference between VAT and sales tax?", a: "VAT is collected throughout the supply chain, while sales tax is usually charged only at the final retail sale." },
  { q: "Which countries have the highest VAT rates?", a: "Several European countries have standard VAT rates above 20%, while rates vary widely across the world." },
  { q: "Can businesses reclaim VAT?", a: "VAT-registered businesses can often reclaim VAT paid on eligible business purchases, subject to local rules." },
];
const COUNTRIES = [
  ["UK", 20, 5, "Reduced rate for some essentials"], ["Germany", 19, 7, "Reduced rate for food/books"], ["France", 20, 5.5, "Multiple reduced rates"], ["Italy", 22, 10, "Reduced rates apply"], ["Spain", 21, 10, "Reduced and super-reduced rates"], ["Australia", 10, 0, "GST system"], ["India", 18, 5, "GST rates vary"], ["UAE", 5, 0, "Standard VAT 5%"], ["Saudi Arabia", 15, 0, "Standard VAT 15%"], ["Canada", 5, 0, "Federal GST plus provinces"], ["Japan", 10, 8, "Reduced food rate"], ["Netherlands", 21, 9, "Reduced rate 9%"], ["Belgium", 21, 6, "Reduced rates apply"], ["Sweden", 25, 12, "High standard rate"], ["Norway", 25, 15, "VAT/MVA"], ["Denmark", 25, 0, "Few reduced rates"], ["Ireland", 23, 13.5, "Reduced rates apply"], ["Poland", 23, 8, "Reduced rates apply"], ["Brazil", 17, 0, "Complex indirect tax"], ["Mexico", 16, 0, "IVA standard rate"],
] as const;
const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function VATCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(100);
  const [mode, setMode] = useState("exclude");
  const [country, setCountry] = useState("UK");
  const [customRate, setCustomRate] = useState(20);
  const rate = country === "Custom" ? customRate : COUNTRIES.find((c) => c[0] === country)?.[1] ?? 20;
  const result = useMemo(() => {
    const r = rate / 100;
    const excluding = mode === "exclude" ? price : price / (1 + r);
    const vat = excluding * r;
    const including = excluding + vat;
    return { excluding, vat, including };
  }, [price, mode, rate]);
  return (
    <>
      <SEOHead title="Free VAT Calculator Online - Calculate VAT Amount and Price Instantly | CalcHive" description="Free online VAT calculator. Calculate VAT amount, price including VAT and price excluding VAT for any rate or country instantly. Includes global VAT rates. 100% free, no signup required." canonical="/vat-calculator" keywords="free VAT calculator, VAT calculator online free, value added tax calculator free, calculate VAT free, price including VAT calculator free online" category="Financial Calculators" breadcrumbName="Free VAT Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free VAT Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate VAT amount, VAT-inclusive price, and VAT-exclusive price by country or custom rate.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Price</label><input type="number" value={price} onChange={(e) => setPrice(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Calculation direction</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="exclude">Price excludes VAT</option><option value="include">Price includes VAT</option></select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Country</label><select value={country} onChange={(e) => setCountry(e.target.value)} className={inputClass}>{COUNTRIES.map((c) => <option key={c[0]}>{c[0]}</option>)}<option>Custom</option></select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">VAT rate (%)</label><input type="number" value={rate} onChange={(e) => { setCountry("Custom"); setCustomRate(Number(e.target.value)); }} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">VAT Amount</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.vat)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Price excluding VAT</p><p className="text-lg font-extrabold text-foreground">{money(result.excluding)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Price including VAT</p><p className="text-lg font-extrabold text-foreground">{money(result.including)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate VAT Amount and Price for Free</h2><p className="text-muted-foreground leading-relaxed">Use this value added tax calculator free to add VAT to a net price or remove VAT from a gross price instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">VAT Rates for Countries Around the World</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">VAT Rates by Country</caption><thead className="bg-muted/60"><tr>{["Country", "Standard VAT Rate", "Reduced Rate", "Notes"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{COUNTRIES.map((row) => <tr key={row[0]}><td className="py-2.5 px-3 font-semibold">{row[0]}</td><td className="py-2.5 px-3">{row[1]}%</td><td className="py-2.5 px-3">{row[2]}%</td><td className="py-2.5 px-3">{row[3]}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Value Added Tax Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">This VAT calculator online free works for invoices, shopping, business pricing, and international tax estimates.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/vat-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


